torch::Tensor avg_pool_3d_cuda(
    torch::Tensor input,
    int kernel_d,
    int kernel_h,
    int kernel_w,
    int stride_d,
    int stride_h,
    int stride_w,
    int pad_d,
    int pad_h,
    int pad_w,
    bool count_include_pad
);
"""

