    """
    Optimized model that performs 3D Average Pooling with custom CUDA kernel.
    """
    def __init__(self, kernel_size: int, stride: int = None, padding: int = 0):
        """
        Initializes the optimized Average Pooling layer.

        Args:
            kernel_size (int): Size of the kernel to apply pooling.
            stride (int, optional): Stride of the pooling operation. Defaults to None, which uses the kernel size.
            padding (int, optional): Padding to apply before pooling. Defaults to 0.
        """
        super(ModelNew, self).__init__()
        self.kernel_size = kernel_size
        self.stride = stride if stride is not None else kernel_size
        self.padding = padding

        # Convert to tuple if single value
        if isinstance(kernel_size, int):
            self.kernel_d = self.kernel_h = self.kernel_w = kernel_size
        else:
            self.kernel_d, self.kernel_h, self.kernel_w = kernel_size

        if isinstance(self.stride, int):
            self.stride_d = self.stride_h = self.stride_w = self.stride
        else:
            self.stride_d, self.stride_h, self.stride_w = self.stride

        if isinstance(padding, int):
            self.pad_d = self.pad_h = self.pad_w = padding
        else:
            self.pad_d, self.pad_h, self.pad_w = padding

        self.count_include_pad = True  # PyTorch default for AvgPool3d

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        """
        Applies optimized Average Pooling to the input tensor using custom CUDA kernel.

        Args:
            x (torch.Tensor): Input tensor of shape (batch_size, channels, depth, height, width).

        Returns:
            torch.Tensor: Output tensor with Average Pooling applied.
