        int idx = linear_idx;
        const int ow = idx % output_width;
        idx /= output_width;
        const int oh = idx % output_height;
        idx /= output_height;
        const int od = idx % output_depth;
        idx /= output_depth;
        const int c = idx % channels;
        idx /= channels;
        const int b = idx;

